CREATE TABLE xeus.bigdata_analy_result${value}
(
mgr_seq
bigserial,
analy_mgr_seq numeric(32,0) NOT NULL,
grid10m_gid numeric(32,0) NOT NULL,
grid100m_gid numeric(32,0) NOT NULL,
jibn_addr character varying(200),
road_addr character varying(200),
result_val numeric(10,0),
rgb_txt character varying(10),
grp_nm character varying(200),
CONSTRAINT bigdata_analy_result${value}_pk PRIMARY KEY (mgr_seq)
);

CREATE INDEX bigdata_analy_result${value}_analy_mgr_seq_idx
ON xeus.bigdata_analy_result${value}
USING btree (analy_mgr_seq);

CREATE INDEX bigdata_analy_result${value}_grid10m_gid_idx
ON xeus.bigdata_analy_result${value}
USING btree (grid10m_gid);

